from collections import Counter

def detect_speaker_bias(messages, agent_ids):
    speakers = [msg.get('speaker') for msg in messages if msg.get('speaker') in agent_ids]
    if not speakers:
        return {'bias_score': 0, 'dominant_speaker': None}

    counts = Counter(speakers)
    total = len(speakers)
    dominant = counts.most_common(1)[0]
    dominance_ratio = dominant[1] / total

    return {
        'bias_score': dominance_ratio,
        'dominant_speaker': dominant[0],
        'alert': dominance_ratio > 0.7,
        'message': f'{dominant[0]} dominates {dominance_ratio:.1%} of conversation'
    }

from sklearn.metrics.pairwise import cosine_similarity
import numpy as np

def detect_echo_chamber(messages):
    from sentence_transformers import SentenceTransformer
    model = SentenceTransformer('all-MiniLM-L6-v2')

    contents = [msg['content'] for msg in messages if len(msg['content']) > 10]
    if len(contents) < 3:
        return {'homogeneity_score': 0}

    embeddings = model.encode(contents)
    similarity_matrix = cosine_similarity(embeddings)
    avg_similarity = np.mean(similarity_matrix[np.triu_indices(len(similarity_matrix), k=1)])

    return {
        'homogeneity_score': avg_similarity,
        'alert': avg_similarity > 0.75,
        'message': f'Average response similarity: {avg_similarity:.1%}'
    }

bias_terms = {
    'gender': ['man', 'woman', 'male', 'female', 'he', 'she'],
    'race': ['black', 'white', 'asian', 'hispanic'],
    'political': ['liberal', 'conservative', 'democrat', 'republican']
}

def detect_bias_keywords(content):
    words = content.lower().split()
    scores = {}

    for category, terms in bias_terms.items():
        count = sum(1 for word in words if any(term in word for term in terms))
        density = count / max(len(words), 1)
        scores[category] = {'density': density, 'alert': density > 0.05}

    max_bias = max(scores.items(), key=lambda x: x[1]['density'])
    return {
        'highest_bias_category': max_bias[0],
        'bias_density': max_bias[1]['density'],
        'alert': max_bias[1]['alert']
    }

