from ag2 import GroupChat, GroupChatManager

class FairSpeakerGroupChat(GroupChat):
    def __init__(self, agents, max_rounds=3):
        super().__init__(agents)
        self.participation_count = {agent.name: 0 for agent in agents}
        self.max_rounds = max_rounds
        self.last_speaker = None

    def select_speaker(self, state):
        eligible = [a for a, count in self.participation_count.items() 
                   if count < self.max_rounds and a != self.last_speaker]
        if eligible:
            speaker = min(eligible, key=lambda a: self.participation_count[a.name])
        else:
            speaker = self.agents[0]  # fallback

        self.participation_count[speaker.name] += 1
        self.last_speaker = speaker
        return speaker

def inject_diversity_prompts(message, history):
    if len(history) > 5:
        perspectives = ['Consider the opposite viewpoint', 
                       'What counterarguments exist?', 
                       'From another cultural perspective...']
        diversity_prompt = perspectives[hash(str(history[-3:])) % len(perspectives)]
        return f"{diversity_prompt}: {message['content']}"
    return message['content']

